\displaystyle{\begin{aligned}
   {\frac{4}{yx+1}-\frac{8yx}{y^{2}x^{2}-1}} 
      \amp = {\frac{4}{yx+1}}-\frac{8 y x}{(y x+1)(y x-1)} \\
      \amp = \frac{4\cdot({yx-1})}{({yx+1})\cdot({yx-1})} -\frac{8 y x}{(y x+1)(y x-1)} \\
      \amp = \frac{{4\mathopen{}\left(yx-1\right)-8yx}}{(yx+1)(yx-1)} \\
      \amp = \frac{{4yx-4-8yx}}{(yx+1)(yx-1)} \\
      \amp = \frac{{-4yx-4}}{(yx+1)(yx-1)} \\
      \amp = \frac{{-4\mathopen{}\left(yx+1\right)}}{(yx+1)(yx-1)} \\
      \amp = {-\frac{4}{yx-1}}
\end{aligned}
    }
